const response = $input.first().json;
const emails = response.emails || [];
if (emails.length === 0) return [{json:{to_email:'',skip:true}}];
const results = [];
const emailRegex = /[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,}/g;
for (const em of emails) {
  const toEmails = (em.to || '').match(emailRegex) || [];
  for (const email of toEmails) {
    results.push({
      json: {
        to_email: email.toLowerCase().trim(),
        subject: em.subject || '',
        body: em.body || '',
        sent_date: new Date(new Date().getTime() + 5*60*60*1000).toISOString().split('T')[0]
      }
    });
  }
}
if (results.length === 0) return [{json:{to_email:'',skip:true}}];
return results;

const sentEmail = $('Extract Sent Details').first().json;
if (sentEmail.skip) return [{json:{found:false}}];
const targetEmail = sentEmail.to_email;
const emailRegex = /[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,}/g;
const allTabs = $('Read All Tabs').first().json;
const ranges = allTabs.valueRanges || [];

function parseTab(values) {
  if (!values || values.length < 2) return [];
  const h = values[0].map(c => c.trim());
  return values.slice(1).map(row => {
    const obj = {};
    h.forEach((col, i) => { obj[col] = (row[i] || '').trim(); });
    return obj;
  });
}

function findEmail(rows, nameCol, companyCol, emailCols, tab) {
  for (const d of rows) {
    const allEmails = [];
    for (const col of emailCols) {
      if (d[col]) {
        const found = d[col].toString().match(emailRegex) || [];
        allEmails.push(...found.map(e => e.toLowerCase().trim()));
      }
    }
    if (allEmails.includes(targetEmail)) {
      return { contact_name: d[nameCol] || 'Contact', company: d[companyCol] || '', tab };
    }
  }
  return null;
}

let matched = null;
if (ranges[0] && ranges[0].values) {
  matched = findEmail(parseTab(ranges[0].values), 'Chief People Officer (CPO) / HR Head', 'Company Name', ['CPO/HR Email', 'Admin Email', 'CPO/HR Generic Email', 'Admin Generic Email'], 'Corporate');
}
if (!matched && ranges[1] && ranges[1].values) {
  matched = findEmail(parseTab(ranges[1].values), 'Chief People Officer (CPO) / HR Head', 'Organization Name', ['CPO/HR Email', 'Admin Email'], 'Non Profit');
}
if (!matched && ranges[2] && ranges[2].values) {
  matched = findEmail(parseTab(ranges[2].values), 'Names', 'Names', ['HR', 'Admin', 'Contact'], 'Universities');
}
if (!matched && ranges[3] && ranges[3].values) {
  matched = findEmail(parseTab(ranges[3].values), 'Chief People Officer (CPO) / HR Head', 'School/College Name', ['CPO/HR Email', 'Admin Email'], 'Colleges');
}

if (matched) {
  return [{json:{
    found:true, email:targetEmail, contact_name:matched.contact_name,
    company:matched.company, subject:sentEmail.subject,
    body_preview:sentEmail.body.substring(0,500), sent_date:sentEmail.sent_date,
    follow_up_count:'0', last_followup_date:sentEmail.sent_date,
    reply_status:'No', status:'Active', source_tab:matched.tab
  }}];
}
return [{json:{found:false}}];

const results = [];
for (const item of $input.all()) {
  const fromRaw = item.json.from?.text || item.json.from || '';
  const emailRegex = /[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,}/g;
  const fromEmails = fromRaw.match(emailRegex) || [];
  for (const email of fromEmails) {
    results.push({ json: { from_email: email.toLowerCase().trim() } });
  }
}
return results;

const sender = $('Extract Reply Sender').first().json;
const trackerRows = $('Read Tracker for Reply').all();
let found = false;
let email = sender.from_email;
for (const row of trackerRows) {
  if (row.json['Email'] && row.json['Email'].toLowerCase().trim() === email && row.json['Reply Status'] !== 'Yes') {
    found = true; break;
  }
}
return [{ json: { found, email } }];

const now = new Date();
const results = [];
for (const item of $input.all()) {
  const row = item.json;
  if (row['Reply Status'] === 'Yes' || row['Status'] === 'Stopped' || row['Status'] === 'Yes') continue;
  const lastDate = row['Last Follow-up Date'] || row['Sent Date'];
  if (!lastDate) continue;
  const last = new Date(lastDate);
  const diffDays = Math.floor((now - last) / (1000 * 60 * 60 * 24));
  if (diffDays >= 2) {
    const count = parseInt(row['Follow-up Count'] || '0') + 1;
    results.push({ json: {
      email: row['Email'], contact_name: row['Contact Name'] || '',
      company: row['Company'] || '', original_subject: row['Subject'] || '',
      original_body: row['Body Preview'] || '',
      follow_up_count: count, today: now.toISOString().split('T')[0]
    }});
  }
}
if (results.length === 0) return [{ json: { email: null } }];
return results;

const item = $input.first().json;
const count = item.follow_up_count;
const name = item.contact_name;
const company = item.company;
const originalSubject = item.original_subject;
const firstName = name.split(' ')[0] || 'there';
const originalBody = item.original_body || '';

let tone = '';
if (count === 1) tone = 'TONE: Gentle first reminder. Mention you sent an email recently. Ask if they had a chance to review it. Suggest a quick 15-min call.';
else if (count === 2) tone = 'TONE: More persuasive second follow-up. Highlight 2-3 specific benefits from original email. Create urgency. Mention how similar companies benefited.';
else if (count === 3) tone = 'TONE: Understanding third follow-up. Acknowledge they are busy. Say you do not want to be a nuisance. Offer to stop if not interested. Give one last compelling reason.';
else tone = 'TONE: Final brief follow-up. Very short (3-4 sentences max). Ask if there is a better person to contact. Offer to reconnect in future.';

const prompt = 'Write follow-up email #' + count + ' for ShareIDE company.

RECIPIENT: ' + firstName + ' at ' + (company || 'their organization') + '
ORIGINAL EMAIL SUBJECT: ' + originalSubject + '
ORIGINAL EMAIL CONTENT: ' + originalBody.replace(/[
]/g, ' ').substring(0, 400) + '

' + tone + '

IMPORTANT RULES:
- This is follow-up #' + count + ' - it MUST be completely different from a first follow-up
- Start with: Dear ' + firstName + ',
- End with: Best regards, ShareIDE Team, hr@shareide.com
- Max 120 words
- No subject line, only email body
- Reference the original email context
- Sound human and natural

Write ONLY the email body:';

return [{ json: { prompt, to_email: item.email, original_subject: originalSubject, follow_up_count: count.toString(), today: item.today, email_for_update: item.email } }];

const promptData = $input.first().json;
const prompt = promptData.prompt;

const data = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  body: {model:'llama-3.3-70b-versatile',messages:[{role:'user',content:prompt}],max_tokens:500,temperature:0.7},
  headers: {'Content-Type':'application/json','Authorization':'Bearer YOUR_GROQ_API_KEY_HERE'}
});

let body = '';
try {
  body = data.choices[0].message.content || '';
} catch(e) {
  body = 'Dear ' + (promptData.to_email.split('@')[0]) + ',\n\nI wanted to follow up on my previous email regarding ' + promptData.original_subject + '. I would appreciate the opportunity to discuss this further.\n\nBest regards,\nShareIDE Team\nhr@shareide.com';
}

const subject = 'Re: ' + promptData.original_subject;

return [{ json: {
  to_email: promptData.to_email,
  subject: subject,
  body: body.trim(),
  follow_up_count: promptData.follow_up_count,
  today: promptData.today,
  email_for_update: promptData.email_for_update
}}];
